// Embed the input text and return a ready-to-paste pgvector literal.
// 5s timeout + shape validation so a flaky embed service does not cascade
// into agent-loop burnout via malformed SQL.
try {
  const resp = await this.helpers.httpRequest({
    method: "POST",
    url: "http://127.0.0.1:8001/embed",
    body: { text: query },
    json: true,
    timeout: 5000,
  });
  if (!resp || !Array.isArray(resp.vector) || resp.vector.length !== 384) {
    return "ERROR: embed service returned invalid response. Skip vector search; answer from query_db on other tables or general knowledge.";
  }
  return "'[" + resp.vector.join(",") + "]'::vector";
} catch (e) {
  return "ERROR: embed service unavailable (" + String(e).slice(0, 200) + "). Skip vector search; answer from query_db on other tables or general knowledge.";
}

// Sum token usage across every Anthropic Chat Model call in this conversation turn.
// n8n's lmChatAnthropic exposes tokenUsage per invocation; .all() gives every call.
let inTok = 0, outTok = 0, calls = 0, model = '';
try {
  const all = $('Anthropic Chat Model').all();
  for (const c of all) {
    const j = c?.json || {};
    // tokenUsage shape varies between n8n versions / langchain versions
    const u = j.tokenUsage || j.usage || j.response?.usage || j.response?.tokenUsage || {};
    inTok  += u.promptTokens     || u.input_tokens  || u.prompt_tokens     || 0;
    outTok += u.completionTokens || u.output_tokens || u.completion_tokens || 0;
    if (!model) model = j.model || j.response?.model || u.model || '';
    calls++;
  }
} catch (e) { /* swallow */ }

// User message (best-effort) — for display in token log
let userMsg = '';
try {
  userMsg = ($('When chat message received').first().json.chatInput || '').slice(0, 500);
} catch (e) {}

// Session id
let sessionId = '';
try {
  sessionId = $('When chat message received').first().json.sessionId || '';
} catch (e) {}

return [{
  json: {
    session_id: sessionId,
    model: model || 'claude-sonnet-4-6',
    input_tokens: inTok,
    output_tokens: outTok,
    calls: calls,
    user_message: userMsg,
    agent_output: $('AI Agent').first().json?.output || ''
  }
}];

parameters.query:
INSERT INTO agent_token_log (session_id, model, input_tokens, output_tokens, user_message)
VALUES ($1, $2, $3, $4, $5)
RETURNING id;

