// Embed the operator's chat input via the local BAAI/bge-small-en-v1.5 service
// and build the SELECT SQL the next Postgres node will execute.
const userMsg = $('When chat message received').first().json.chatInput || '';
let vector = [];
let embedError = null;
try {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'http://127.0.0.1:8001/embed',
    body: { text: userMsg },
    json: true,
  });
  vector = resp.vector || [];
} catch (e) {
  embedError = String(e).slice(0, 300);
}
const vecLit = vector.length > 0 ? '[' + vector.join(',') + ']' : null;
const sql = vecLit
  ? "SELECT id, memory_type, title, content, importance, ROUND((1 - (embedding <=> '" + vecLit + "'::vector))::numeric, 4) AS similarity FROM memories WHERE expires_at IS NULL OR expires_at > NOW() ORDER BY embedding <=> '" + vecLit + "'::vector LIMIT 5"
  : 'SELECT NULL::bigint AS id, NULL::text AS memory_type, NULL::text AS title, NULL::text AS content, NULL::smallint AS importance, NULL::numeric AS similarity WHERE FALSE';
return [{ json: { user_query: userMsg, vector_dim: vector.length, embed_error: embedError, sql } }];

// Format retrieved memory rows into a markdown block injected into
// the AI Agent system prompt as runtime context. Template literals are used
// throughout so multi-line strings + apostrophes parse correctly after the
// workflow JSON is deserialized by n8n (single-quoted multi-lines were the
// bug that timed out the task runner).
const rows = $input.all().map(item => item.json).filter(r => r && r.id != null);
let block = '';
if (rows.length > 0) {
  let body = '';
  for (const m of rows) {
    const snippet = (m.content || '').slice(0, 300).replace(/\n/g, ' ');
    body += `- **[${m.memory_type}]** *${m.title}* (importance ${m.importance}, similarity ${m.similarity}): ${snippet}\n`;
  }
  block = `\n\n## Past relevant context (semantic memory recall, auto-injected for this turn)\n\nThe memories below are the top-K semantically most similar past memories to the current question. Reference them when relevant; if you see a recurring pattern or a past incident matching, name it explicitly.\n\n${body}`;
}
return [{ json: { memoryBlock: block, retrieved_count: rows.length } }];
